import React from "react";
import "./Banner.css";

// Swiper imports
import { Swiper, SwiperSlide } from "swiper/react";
import "swiper/css";

function Banner() {
  return (
    <div className="banner">
      <Swiper spaceBetween={10} slidesPerView={1} autoplay={{ delay: 2000 }}>

        <SwiperSlide>
          <img src="https://rukminim1.flixcart.com/fk-p-flap/1600/270/image/1.jpg" alt="banner1" />
        </SwiperSlide>

        <SwiperSlide>
          <img src="https://rukminim1.flixcart.com/fk-p-flap/1600/270/image/2.jpg" alt="banner2" />
        </SwiperSlide>

        <SwiperSlide>
          <img src="https://rukminim1.flixcart.com/fk-p-flap/1600/270/image/3.jpg" alt="banner3" />
        </SwiperSlide>

      </Swiper>
    </div>
  );
}

export default Banner;
